                 let storage_guard = storage.read_with_cx(cx).await;
                 storage_guard
-                    .is_event_muted(&identity_key, now_ms)
+                    .is_event_muted_with_cx(cx, &identity_key, now_ms)
                     .await
                     .unwrap_or(false)
             };
